import React, { useEffect, useRef, useState } from 'react';

export default function AudioCall({ socket, currentUser, callState, onEnd }) {
  // callState: { type: 'outgoing'|'incoming'|'active', peer, offer? }
  const [muted, setMuted] = useState(false);
  const [duration, setDuration] = useState(0);
  const [status, setStatus] = useState(callState.type === 'outgoing' ? 'Calling...' : 'Incoming call');

  const pcRef = useRef(null);
  const localStreamRef = useRef(null);
  const remoteAudioRef = useRef(null);
  const timerRef = useRef(null);

  const avatarColor = (name) => {
    const colors = ['linear-gradient(135deg,#e8748a,#c9a96e)', 'linear-gradient(135deg,#f59e0b,#ef4444)', 'linear-gradient(135deg,#10b981,#3b82f6)'];
    return colors[(name?.charCodeAt(0) || 0) % colors.length];
  };

  const startTimer = () => {
    timerRef.current = setInterval(() => setDuration(d => d + 1), 1000);
  };

  const formatDuration = (s) => `${String(Math.floor(s / 60)).padStart(2, '0')}:${String(s % 60).padStart(2, '0')}`;

  const createPC = async () => {
    const pc = new RTCPeerConnection({
      iceServers: [{ urls: 'stun:stun.l.google.com:19302' }, { urls: 'stun:stun1.l.google.com:19302' }]
    });
    pcRef.current = pc;

    // Get local audio
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    localStreamRef.current = stream;
    stream.getTracks().forEach(t => pc.addTrack(t, stream));

    // Remote audio
    pc.ontrack = (e) => {
      if (remoteAudioRef.current) {
        remoteAudioRef.current.srcObject = e.streams[0];
        remoteAudioRef.current.play().catch(() => {});
      }
    };

    // ICE candidates
    pc.onicecandidate = (e) => {
      if (e.candidate) {
        socket.emit('call:ice', { to: callState.peer, candidate: e.candidate });
      }
    };

    pc.onconnectionstatechange = () => {
      if (pc.connectionState === 'connected') {
        setStatus('Connected');
        startTimer();
      }
      if (['disconnected', 'failed', 'closed'].includes(pc.connectionState)) {
        endCall(false);
      }
    };

    return pc;
  };

  // Outgoing — create offer
  useEffect(() => {
    if (callState.type !== 'outgoing') return;
    (async () => {
      const pc = await createPC();
      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);
      socket.emit('call:offer', { to: callState.peer, from: currentUser.username, offer });
    })();
  }, []);

  // Incoming — auto setup PC ready for answer
  useEffect(() => {
    if (callState.type !== 'incoming') return;
    (async () => {
      await createPC();
    })();
  }, []);

  // Socket listeners
  useEffect(() => {
    const handleAnswer = async ({ answer }) => {
      if (pcRef.current) {
        await pcRef.current.setRemoteDescription(new RTCSessionDescription(answer));
        setStatus('Connected');
        startTimer();
      }
    };

    const handleIce = async ({ candidate }) => {
      if (pcRef.current && candidate) {
        try { await pcRef.current.addIceCandidate(new RTCIceCandidate(candidate)); } catch {}
      }
    };

    const handleEnded = () => endCall(false);
    const handleRejected = () => { setStatus('Call declined'); setTimeout(() => endCall(false), 1500); };
    const handleBusy = () => { setStatus('User is busy'); setTimeout(() => endCall(false), 1500); };

    socket.on('call:answer', handleAnswer);
    socket.on('call:ice', handleIce);
    socket.on('call:ended', handleEnded);
    socket.on('call:rejected', handleRejected);
    socket.on('call:busy', handleBusy);

    return () => {
      socket.off('call:answer', handleAnswer);
      socket.off('call:ice', handleIce);
      socket.off('call:ended', handleEnded);
      socket.off('call:rejected', handleRejected);
      socket.off('call:busy', handleBusy);
    };
  }, []);

  const acceptCall = async () => {
    setStatus('Connecting...');
    const pc = pcRef.current;
    await pc.setRemoteDescription(new RTCSessionDescription(callState.offer));
    const answer = await pc.createAnswer();
    await pc.setLocalDescription(answer);
    socket.emit('call:answer', { to: callState.peer, answer });
  };

  const rejectCall = () => {
    socket.emit('call:reject', { to: callState.peer });
    endCall(false);
  };

  const endCall = (notify = true) => {
    clearInterval(timerRef.current);
    if (notify) socket.emit('call:end', { to: callState.peer });
    if (pcRef.current) { pcRef.current.close(); pcRef.current = null; }
    if (localStreamRef.current) localStreamRef.current.getTracks().forEach(t => t.stop());
    onEnd();
  };

  const toggleMute = () => {
    if (localStreamRef.current) {
      localStreamRef.current.getAudioTracks().forEach(t => { t.enabled = muted; });
      setMuted(m => !m);
    }
  };

  const isIncoming = callState.type === 'incoming';
  const isActive = status === 'Connected';

  return (
    <div className="anim-fadeIn" style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.85)', backdropFilter: 'blur(12px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 3000 }}>
      <audio ref={remoteAudioRef} autoPlay />

      <div className="anim-scaleIn" style={{ background: 'linear-gradient(160deg, #2e1820, #1a0e14)', border: '1px solid #4e2830', borderRadius: 28, padding: '40px 32px', width: 320, textAlign: 'center', boxShadow: '0 32px 80px rgba(0,0,0,0.7)' }}>

        {/* Avatar with pulse */}
        <div style={{ position: 'relative', display: 'inline-block', marginBottom: 20 }}>
          {(isIncoming || isActive) && (
            <>
              <div style={{ position: 'absolute', inset: -12, borderRadius: '50%', border: '2px solid rgba(232,116,138,0.3)', animation: 'statusRing 1.5s ease infinite' }} />
              <div style={{ position: 'absolute', inset: -24, borderRadius: '50%', border: '2px solid rgba(232,116,138,0.15)', animation: 'statusRing 1.5s ease 0.3s infinite' }} />
            </>
          )}
          <div style={{ width: 80, height: 80, borderRadius: '50%', background: avatarColor(callState.peer), display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 32, fontWeight: 700, color: '#fff', position: 'relative', zIndex: 1 }}>
            {callState.peer[0].toUpperCase()}
          </div>
        </div>

        {/* Name */}
        <div style={{ fontSize: 22, fontWeight: 700, color: '#f5e6e8', marginBottom: 6 }}>{callState.peer}</div>

        {/* Status / Duration */}
        <div style={{ fontSize: 14, color: isActive ? '#4ade80' : '#c9a0a8', marginBottom: 32, minHeight: 20 }}>
          {isActive ? formatDuration(duration) : status}
        </div>

        {/* Buttons */}
        {isIncoming && status === 'Incoming call' ? (
          // Incoming — accept / reject
          <div style={{ display: 'flex', justifyContent: 'center', gap: 32 }}>
            <div style={{ textAlign: 'center' }}>
              <button onClick={rejectCall} style={{ width: 60, height: 60, borderRadius: '50%', background: 'rgba(248,113,113,0.15)', border: '2px solid rgba(248,113,113,0.4)', color: '#f87171', fontSize: 24, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 8px', transition: 'transform 0.15s' }}
                onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.1)'}
                onMouseLeave={e => e.currentTarget.style.transform = 'scale(1)'}
              >📵</button>
              <div style={{ fontSize: 11, color: '#f87171' }}>Decline</div>
            </div>
            <div style={{ textAlign: 'center' }}>
              <button onClick={acceptCall} style={{ width: 60, height: 60, borderRadius: '50%', background: 'rgba(74,222,128,0.15)', border: '2px solid rgba(74,222,128,0.4)', color: '#4ade80', fontSize: 24, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 8px', transition: 'transform 0.15s', animation: 'onlinePulse 1s ease infinite' }}
                onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.1)'}
                onMouseLeave={e => e.currentTarget.style.transform = 'scale(1)'}
              >📞</button>
              <div style={{ fontSize: 11, color: '#4ade80' }}>Accept</div>
            </div>
          </div>
        ) : (
          // Outgoing / Active — mute + end
          <div style={{ display: 'flex', justifyContent: 'center', gap: 24 }}>
            <div style={{ textAlign: 'center' }}>
              <button onClick={toggleMute} style={{ width: 54, height: 54, borderRadius: '50%', background: muted ? 'rgba(232,116,138,0.2)' : 'rgba(255,255,255,0.08)', border: `2px solid ${muted ? 'rgba(232,116,138,0.5)' : 'rgba(255,255,255,0.15)'}`, color: muted ? '#e8748a' : '#f5e6e8', fontSize: 20, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 8px', transition: 'all 0.2s' }}>
                {muted ? '🔇' : '🎙️'}
              </button>
              <div style={{ fontSize: 11, color: '#c9a0a8' }}>{muted ? 'Unmute' : 'Mute'}</div>
            </div>
            <div style={{ textAlign: 'center' }}>
              <button onClick={() => endCall(true)} style={{ width: 54, height: 54, borderRadius: '50%', background: 'rgba(248,113,113,0.15)', border: '2px solid rgba(248,113,113,0.4)', color: '#f87171', fontSize: 20, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 8px', transition: 'transform 0.15s' }}
                onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.1)'}
                onMouseLeave={e => e.currentTarget.style.transform = 'scale(1)'}
              >📵</button>
              <div style={{ fontSize: 11, color: '#f87171' }}>End</div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
